CODE_EXAMPLE:
public class Invoice {
  public List<InvoiceLine> Lines { get; } = new List<InvoiceLine>();
}

public class InvoiceCalculator {
  public decimal Total(Invoice invoice) => invoice.Lines.Sum(l => l.Price * l.Quantity);
}

public class InvoiceWithMovedMethod {
  public List<InvoiceLine> Lines { get; } = new List<InvoiceLine>();
  public decimal Total() => Lines.Sum(l => l.Price * l.Quantity);
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Total_InTargetClass_ComputesExpectedValue() {
  var invoice = new InvoiceWithMovedMethod();
  invoice.Lines.Add(new InvoiceLine(10m, 2));
  Assert.AreEqual(20m, invoice.Total());
}

[TestMethod]
public void MovedMethod_PreservesCalculationLogic() {
  var invoice = new InvoiceWithMovedMethod();
  invoice.Lines.Add(new InvoiceLine(7m, 3));
  Assert.AreEqual(21m, invoice.Total());
}
